  ('locality-6f0ba476-moex-00159', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '我國稅法關於自用住宅的相關規定之敘述，下列何者正確？', '["各種稅目的重購退稅，不論是出售房地或新購入房地都必須按自用住宅用地稅率課稅", "土地增值稅一生一次按自用住宅用地稅率課稅，適用條件之一是土地所有權人或其配偶、直系 親屬於出售前一年要辦竣戶籍登記", "申請土地增值稅重購退稅，土地所有權人必須是同一人，但建物所有權人可以是本人、配偶或 直系親屬", "地價稅自用住宅用地面積限制為都市土地3公畝，非都市土地7公畝，但不可同時享受自用住 宅優惠，須依比率換算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00160', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '國稅局於110年5月1日將營利事業所得稅核定稅額通知書及繳款書合法送達甲公司，甲公司於 110年5月10日提起復查，112年5月21日為核課期間屆滿日，112年3月15日法院判決確定 撤銷國稅局原核定處分，假設題目及選項之期日或期間末日均非假日，下列何者正確？', '["國稅局應重新核定的期限為112年5月21日", "適用時效中斷之規定", "不適用時效不完成之規定", "國稅局應重新核定的期限為113年3月14日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00161', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '下列那些稅捐的稅課收入可指定用於長期照顧服務支出或長期照顧資源發展？①遺產稅及贈與稅', '["房地合一稅", "營業稅", "菸酒稅  ⑤菸品健康福利捐", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00162', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '有關房屋稅之敘述，下列何者錯誤？①繼承取得共有房屋之稅率為 1.5%～2.4%  ②房屋稅以每', '["房屋稅為地方稅，直轄市及縣（市）政府 歸戶個人所有房屋，供本人、配偶及未成年子女合計3戶以內享有自住優惠稅率1.2%，超過3戶 則課徵差別稅率", "營利事業所有房屋現值在新臺幣10萬元以下者免徵房屋稅  ⑤起造人持有 住家用之待售房屋，於起課房屋稅二年內，稅率最低不得少於2%，最高不得超過3.6%", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00163', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '張君為經常居住於中華民國境內的國民，民國80年與甲女結婚，兩人約定採共同財產制。張君 於113年過世，死亡時遺留的財產總額為2,800萬元，均為婚後財產，其中包括甲女一年前贈與 現金300萬元。甲女財產為2,500萬元（其中包括結婚前財產800萬元，以及兩年前父親贈與200 萬元），另有銀行貸款300萬元。依民法第1030條之1的規定生存配偶主張剩餘財產差額分配 請求權，得自遺產總額中扣除多少金額？', '["650萬元", "150萬元", "800萬元", "0元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "e76084a7e056", "answer_pdf_sha1": "6440ab763a6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
